import React from 'react';

export default function VideoPlayer({ url }) {
  if (!url) return null;

  return (
    <video
      src={url}
      controls
      style={{
        width: '100%',
        borderRadius: '8px',
        background: '#000',
        maxHeight: '360px',
        objectFit: 'contain',
      }}
    />
  );
}
